import { useState, useEffect } from 'react';
import { motion } from 'framer-motion';
import { Sword } from 'lucide-react';

const CodeArenaIntro = ({ onComplete }) => {
  const [stage, setStage] = useState('start');

  useEffect(() => {
    let mounted = true;
    const sequence = async () => {
      // 1. Start: Swords fly in
      await new Promise(r => setTimeout(r, 100));
      if (!mounted) return;
      setStage('clash');

      // 2. Clash moment: Swords cross
      await new Promise(r => setTimeout(r, 1000));
      if (!mounted) return;
      setStage('text'); // Show text

      // 3. Hold and Reveal
      await new Promise(r => setTimeout(r, 1000));
      if (!mounted) return;
      
      // 4. Trigger Layout Transition
      onComplete();
    };
    sequence();
    return () => { mounted = false; };
  }, [onComplete]);

  // Framer Motion variants for cleaner code
  const containerVariants = {
    start: { opacity: 0 },
    clash: { opacity: 1 },
    text: { opacity: 1 },
    exit: { opacity: 0 }
  };

  return (
    <motion.div 
      className="fixed inset-0 z-[100] flex items-center justify-center pointer-events-none"
    >
      {/* Background Layer - Fades out */}
      <motion.div 
        className="absolute inset-0 bg-slate-50"
        initial={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        transition={{ duration: 0.8, ease: "easeInOut" }}
      />

      <div className="relative flex items-center justify-center z-10">
        <div className="flex items-center space-x-4">
            
            {/* The Logo Container (transitioning using layoutId) */}
            <motion.div 
                layoutId="logo-icon"
                className="relative w-24 h-24 flex items-center justify-center text-blue-600"
            >
               {/* Left Sword (pointing top-right in cross) */}
               <motion.div
                  initial={{ x: -60, y: 60, opacity: 0, rotate: -45 }}
                  animate={stage !== 'start' ? { x: 0, y: 0, opacity: 1, rotate: 0 } : {}}
                  transition={{ type: "spring", stiffness: 100, damping: 12, duration: 0.8 }}
                  className="absolute inset-0 flex items-center justify-center"
               >
                 {/* Single Sword Icon, rotated to form one half of X */}
                 <Sword size={64} absoluteStrokeWidth className="transform scale-x-[-1]" />
               </motion.div>

               {/* Right Sword (pointing top-left in cross) */}
               <motion.div
                  initial={{ x: 60, y: 60, opacity: 0, rotate: 45 }}
                  animate={stage !== 'start' ? { x: 0, y: 0, opacity: 1, rotate: 0 } : {}}
                  transition={{ type: "spring", stiffness: 100, damping: 12, duration: 0.8, delay: 0.1 }}
                  className="absolute inset-0 flex items-center justify-center"
               >
                 <Sword size={64} absoluteStrokeWidth />
               </motion.div>

               {/* Add a subtle clash effect (spark or flash) */}
                 {stage === 'clash' && (
                    <motion.div
                        className="absolute w-12 h-12 bg-blue-400 rounded-full blur-xl opacity-0"
                        animate={{ opacity: [0, 0.8, 0], scale: [0.5, 1.5, 1] }}
                        transition={{ duration: 0.4 }}
                    />
                 )}
            </motion.div>

            {/* Text Reveal */}
            <div className="overflow-hidden">
                <motion.h1
                    layoutId="logo-text"
                    initial={{ width: 0, opacity: 0, x: -20 }}
                    animate={stage === 'text' || stage === 'finish' ? { width: 'auto', opacity: 1, x: 0 } : { width: 0, opacity: 0, x: -20 }}
                    transition={{ duration: 0.8, ease: "circOut" }}
                    className="text-6xl font-bold text-slate-900 font-mono tracking-tighter whitespace-nowrap"
                >
                    CodeArena_
                </motion.h1>
            </div>
        </div>
      </div>
    </motion.div>
  );
};

export default CodeArenaIntro;

import React, { useState } from "react";
import { Terminal, Lock, User, Check, ArrowRight, X } from "lucide-react";
import { useNavigate, Link } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import API_BASE from "../config/api";


export default function LoginModal({ isOpen, onClose, onSwitchToSignup }) {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    identifier: "",
    password: "",
    rememberMe: false,
  });

  const [focusedField, setFocusedField] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setError("");
    setFormData((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (!formData.identifier || !formData.password) {
      setError("Please fill in all fields");
      return;
    }

    setIsLoading(true);

    try {
      const response = await fetch(`${API_BASE}/api/auth/login`, {

        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          email: formData.identifier,
          password: formData.password,
        }),
      });

      const data = await response.json();

      if (response.ok) {
        localStorage.setItem("token", data.token);
        const userToSave = {
          _id: data.user._id,
          username: data.user.username,
          email: data.user.email
        };
        localStorage.setItem("user", JSON.stringify(userToSave));
        onClose(); // Close modal on success
        navigate("/dashboard", { replace: true });
      } else {
        setError(data.message || "Login failed");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
          />

          <motion.div
            initial={{ scale: 0.95, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.95, opacity: 0, y: 20 }}
            className="relative w-full max-w-md bg-white dark:bg-slate-900 rounded-2xl shadow-2xl overflow-hidden z-10 border border-slate-200 dark:border-slate-800"
          >
            {/* Close Button */}
            <button
              onClick={onClose}
              className="absolute top-4 right-4 p-2 text-slate-400 dark:text-slate-500 hover:text-slate-600 dark:hover:text-slate-300 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-full transition-colors z-20"
            >
              <X size={20} />
            </button>

            <div className="p-8">
              <div className="text-center mb-8">
                <div className="inline-flex items-center justify-center w-12 h-12 bg-blue-100 dark:bg-blue-900/30 rounded-xl mb-4 text-blue-600 dark:text-blue-400">
                  <Terminal size={24} />
                </div>
                <h2 className="text-2xl font-bold text-slate-900 dark:text-white mb-2">Access CodeArena</h2>
                <p className="text-slate-500 dark:text-slate-400 text-sm">Login to start your battle session.</p>
              </div>

              <form className="space-y-5" onSubmit={handleSubmit}>
                {/* Identifier */}
                <div className="group">
                  <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider mb-1.5 ml-1">
                    Username or Email
                  </label>
                  <div className={`flex items-center bg-slate-50 dark:bg-slate-800 border rounded-lg transition-all ${focusedField === "identifier" ? "border-blue-600 ring-1 ring-blue-600 bg-white dark:bg-slate-900" : "border-slate-200 dark:border-slate-700"}`}>
                    <div className="pl-4 text-slate-400"><User size={18} /></div>
                    <input
                      type="text"
                      name="identifier"
                      value={formData.identifier}
                      onChange={handleInputChange}
                      onFocus={() => setFocusedField("identifier")}
                      onBlur={() => setFocusedField(null)}
                      className="w-full bg-transparent text-slate-900 p-3.5 focus:outline-none placeholder-slate-400 font-medium"
                      placeholder="Enter credentials"
                    />
                  </div>
                </div>

                {/* Password */}
                <div className="group">
                  <div className="flex justify-between items-center mb-1.5 ml-1">
                    <label className="block text-xs font-semibold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Password</label>
                    <a href="#" className="text-xs font-medium text-blue-600 dark:text-blue-400 hover:underline">Forgot?</a>
                  </div>
                  <div className={`flex items-center bg-slate-50 dark:bg-slate-800 border rounded-lg transition-all ${focusedField === "password" ? "border-blue-600 ring-1 ring-blue-600 bg-white dark:bg-slate-900" : "border-slate-200 dark:border-slate-700"}`}>
                    <div className="pl-4 text-slate-400"><Lock size={18} /></div>
                    <input
                      type="password"
                      name="password"
                      value={formData.password}
                      onChange={handleInputChange}
                      onFocus={() => setFocusedField("password")}
                      onBlur={() => setFocusedField(null)}
                      className="w-full bg-transparent text-slate-900 p-3.5 focus:outline-none placeholder-slate-400 font-medium"
                      placeholder="••••••••"
                    />
                  </div>
                </div>

                {/* Error & Submit */}
                {error && <div className="text-red-500 text-sm font-medium text-center bg-red-50 p-2 rounded">{error}</div>}

                <button
                  type="submit"
                  disabled={isLoading}
                  className="w-full flex items-center justify-center gap-2 p-4 bg-blue-600 hover:bg-blue-700 text-white rounded-lg font-bold transition-all disabled:opacity-70 disabled:cursor-not-allowed shadow-lg shadow-blue-500/30"
                >
                  {isLoading ? "AUTHENTICATING..." : "LOGIN TO BATTLE"}
                  {!isLoading && <ArrowRight size={18} />}
                </button>
              </form>

              <div className="mt-6 text-center text-sm text-slate-500 dark:text-slate-400">
                New warrior? <button onClick={onSwitchToSignup} className="text-blue-600 dark:text-blue-400 font-bold hover:underline">Create Account</button>
              </div>
            </div>
          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

import { useState } from 'react';
import { useNavigate, useLocation } from 'react-router-dom';
import {
  Swords, Terminal as TerminalIcon, LogOut, Menu, X, User, ChevronDown, Sun, Moon
} from 'lucide-react';
import { motion, AnimatePresence } from 'framer-motion';
import { useTheme } from '../context/ThemeContext';

export default function Navbar({ items = [], user = null, onLogout }) {
  const navigate = useNavigate();
  const location = useLocation();
  const { theme, toggleTheme } = useTheme();
  const [isMenuOpen, setIsMenuOpen] = useState(false);
  const [isProfileOpen, setIsProfileOpen] = useState(false);
  const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);

  const handleLogout = () => {
    setShowLogoutConfirm(false);
    if (onLogout) onLogout();
    else {
      localStorage.removeItem('token');
      localStorage.removeItem('user');
      navigate('/login');
    }
  };

  return (
    <>
      <header className="bg-white/80 dark:bg-slate-900/80 backdrop-blur-md border-b border-slate-200 dark:border-slate-800 sticky top-0 z-50 h-16 transition-all duration-300">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 h-full">
          <div className="flex justify-between items-center h-full">

            <div className="flex items-center space-x-2 cursor-pointer" onClick={() => navigate(user ? '/dashboard' : '/')}>
              <Swords className="w-8 h-8 text-blue-600 dark:text-blue-400" />
              <h1 className="text-xl font-bold text-slate-900 dark:text-white font-mono tracking-tighter">CodeArena_</h1>
            </div>

            {/* Desktop Navigation */}
            <nav className="hidden md:flex space-x-8 font-mono text-sm h-full">
              {items.map((item, index) => (
                <button
                  key={index}
                  onClick={item.action}
                  className={`group relative flex items-center h-full font-medium transition-colors ${location.pathname === item.path ? 'text-blue-600 dark:text-blue-400' : 'text-slate-600 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400'
                    }`}
                >
                  {item.label}
                  <span className={`absolute bottom-0 left-0 w-full h-[3px] bg-blue-600 transition-transform duration-300 ease-out ${location.pathname === item.path ? 'scale-x-100' : 'scale-x-0 group-hover:scale-x-100'
                    }`}></span>
                </button>
              ))}
            </nav>

            {/* Right Side Actions */}
            <div className="flex items-center space-x-4">
              {user ? (
                // Authenticated View
                // Authenticated View
                <div className="hidden md:flex items-center space-x-4">
                  {/* Profile Dropdown */}
                  <div className="relative">
                    <button
                      onClick={() => setIsProfileOpen(!isProfileOpen)}
                      className="flex items-center gap-2 p-1 pr-3 rounded-full border border-slate-200 dark:border-slate-700 hover:border-blue-300 dark:hover:border-blue-500 hover:bg-slate-50 dark:hover:bg-slate-800 transition-all group"
                    >
                      <div className="w-8 h-8 rounded-full bg-purple-600 text-white flex items-center justify-center font-bold text-sm shadow-sm">
                        {user.username.charAt(0).toUpperCase()}
                      </div>
                      <ChevronDown size={16} className={`text-slate-400 group-hover:text-slate-600 transition-transform duration-200 ${isProfileOpen ? 'rotate-180' : ''}`} />
                    </button>

                    <AnimatePresence>
                      {isProfileOpen && (
                        <motion.div
                          initial={{ opacity: 0, y: 10, scale: 0.95 }}
                          animate={{ opacity: 1, y: 0, scale: 1 }}
                          exit={{ opacity: 0, y: 10, scale: 0.95 }}
                          className="absolute right-0 top-full mt-2 w-56 bg-white dark:bg-slate-900 rounded-xl shadow-xl border border-slate-100 dark:border-slate-800 py-2 overflow-hidden z-50 transform origin-top-right"
                        >
                          <div className="px-4 py-3 border-b border-slate-50 dark:border-slate-800 bg-slate-50/50 dark:bg-slate-800/50 mb-1">
                            <p className="text-[10px] text-slate-500 dark:text-slate-400 uppercase tracking-wider font-bold">Signed in as</p>
                            <p className="text-sm font-bold text-slate-900 dark:text-white truncate font-mono">{user.username}</p>
                          </div>

                          <button
                            onClick={() => { navigate(`/profile/${user._id}`); setIsProfileOpen(false); }}
                            className="w-full text-left px-4 py-2 text-sm text-slate-600 dark:text-slate-400 hover:bg-slate-50 dark:hover:bg-slate-800 hover:text-blue-600 dark:hover:text-blue-400 flex items-center gap-3 transition-colors font-medium group"
                          >
                            <User size={16} className="text-slate-400 dark:text-slate-500 group-hover:text-blue-500" />
                            Profile
                          </button>

                          <div className="h-px bg-slate-100 dark:bg-slate-800 my-1"></div>

                          <button
                            onClick={() => { setShowLogoutConfirm(true); setIsProfileOpen(false); }}
                            className="w-full text-left px-4 py-2 text-sm text-red-600 dark:text-red-400 hover:bg-red-50 dark:hover:bg-red-900/20 flex items-center gap-3 transition-colors font-medium"
                          >
                            <LogOut size={16} />
                            Logout
                          </button>
                        </motion.div>
                      )}
                    </AnimatePresence>
                  </div>
                </div>
              ) : (
                // Public View
                <div className="hidden md:flex items-center space-x-4">
                  <button onClick={() => navigate('/login')} className="text-slate-600 dark:text-slate-400 hover:text-slate-900 dark:hover:text-white font-medium font-mono text-sm">Log_In</button>
                  <button
                    onClick={() => navigate('/signup')}
                    className="bg-slate-900 dark:bg-blue-600 text-white px-5 py-2 rounded-md hover:bg-slate-800 dark:hover:bg-blue-700 font-medium shadow-lg shadow-slate-200 dark:shadow-none transition-all hover:shadow-xl active:scale-95"
                  >
                    Get Started
                  </button>
                </div>
              )}

              {/* Theme Toggle Button */}
              <button
                onClick={toggleTheme}
                className="p-2 rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 transition-all border border-slate-200 dark:border-slate-700"
                aria-label="Toggle Theme"
              >
                {theme === 'light' ? <Moon size={20} /> : <Sun size={20} />}
              </button>

              {/* Mobile Menu Toggle */}
              <button
                className="md:hidden text-slate-600 hover:text-blue-600 transition-colors"
                onClick={() => setIsMenuOpen(!isMenuOpen)}
              >
                {isMenuOpen ? <X /> : <Menu />}
              </button>
            </div>
          </div>
        </div>

        {/* Mobile Menu - Classic & Premium */}
        <AnimatePresence>
          {isMenuOpen && (
            <motion.div
              initial={{ opacity: 0, height: 0 }}
              animate={{ opacity: 1, height: 'auto' }}
              exit={{ opacity: 0, height: 0 }}
              transition={{ duration: 0.3, ease: "easeInOut" }}
              className="md:hidden absolute top-16 left-0 w-full bg-white/95 dark:bg-slate-900/95 backdrop-blur-xl border-b border-slate-200 dark:border-slate-800 shadow-2xl z-30 overflow-hidden"
            >
              <div className="px-6 py-8 space-y-6 font-mono">
                <div className="space-y-4">
                  {items.map((item, idx) => (
                    <button
                      key={idx}
                      onClick={() => { item.action(); setIsMenuOpen(false); }}
                      className="block w-full text-left px-4 text-slate-600 dark:text-slate-400 hover:text-blue-600 dark:hover:text-blue-400 transition-colors font-medium text-lg font-mono"
                    >
                      {item.label}
                    </button>
                  ))}
                </div>

                <div className="h-px bg-slate-100 dark:bg-slate-800 w-full my-6 transition-colors"></div>

                <div className="px-2">
                  {user ? (
                    <div className="space-y-4">
                      <button onClick={() => { navigate(`/profile/${user._id}`); setIsMenuOpen(false); }} className="flex items-center justify-center w-full py-3 text-slate-600 dark:text-slate-400 font-bold border border-slate-200 dark:border-slate-800 rounded-lg hover:border-blue-400 dark:hover:border-blue-500 hover:text-blue-600 dark:hover:text-blue-400 transition-all gap-2">
                        <User size={18} /> Profile
                      </button>
                      <button onClick={handleLogout} className="flex items-center justify-center w-full py-3 text-red-600 dark:text-red-400 font-bold border border-red-100 dark:border-red-900/20 rounded-lg hover:bg-red-50 dark:hover:bg-red-900/40 transition-all gap-2">
                        <LogOut size={18} /> Logout
                      </button>
                    </div>
                  ) : (
                    <div className="grid grid-cols-2 gap-4">
                      <button onClick={() => { navigate('/login'); setIsMenuOpen(false); }} className="flex items-center justify-center py-3 text-slate-600 dark:text-slate-400 font-bold border border-slate-200 dark:border-slate-800 rounded-lg hover:border-slate-400 dark:hover:border-slate-600 hover:text-slate-900 dark:hover:text-white transition-all">
                        Log_In
                      </button>
                      <button onClick={() => { navigate('/signup'); setIsMenuOpen(false); }} className="flex items-center justify-center py-3 text-slate-900 dark:text-white font-bold border-2 border-slate-900 dark:border-blue-600 rounded-lg hover:bg-slate-50 dark:hover:bg-slate-800 transition-all">
                        Sign_Up
                      </button>
                    </div>
                  )}
                </div>
              </div>
            </motion.div>
          )}
        </AnimatePresence>
      </header>

      {/* Logout Confirmation Modal */}
      {showLogoutConfirm && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center bg-black/50 backdrop-blur-sm">
          <div className="bg-white dark:bg-slate-900 rounded-xl shadow-2xl border border-slate-200 dark:border-slate-800 p-6 max-w-sm w-full mx-4 transform transition-all scale-100">
            <h3 className="text-xl font-bold text-slate-900 dark:text-white mb-2">Confirm Logout</h3>
            <p className="text-slate-500 dark:text-slate-400 mb-6">
              Are you sure you want to terminate your session?
            </p>
            <div className="flex justify-end gap-3">
              <button
                onClick={() => setShowLogoutConfirm(false)}
                className="px-4 py-2 text-slate-600 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800 rounded-lg font-medium transition-colors"
              >
                Cancel
              </button>
              <button
                onClick={handleLogout}
                className="px-4 py-2 bg-red-600 text-white hover:bg-red-700 rounded-lg font-medium transition-colors flex items-center gap-2"
              >
                <LogOut size={16} />
                <span>Logout</span>
              </button>
            </div>
          </div>
        </div>
      )}
    </>
  );
}

import React, { useState } from "react";
import { Terminal, Lock, User, Mail, Check, ArrowRight, X } from "lucide-react";
import { useNavigate } from "react-router-dom";
import { motion, AnimatePresence } from "framer-motion";
import { API_BASE_URL } from "../config/api";
import { login } from "../utils/auth";

export default function SignupModal({ isOpen, onClose, onSwitchToLogin, redirectTo }) {
  const navigate = useNavigate();
  const [formData, setFormData] = useState({
    username: "",
    email: "",
    password: "",
    confirmPassword: "",
    agreed: false
  });

  const [focusedField, setFocusedField] = useState(null);
  const [error, setError] = useState("");
  const [isLoading, setIsLoading] = useState(false);

  const handleInputChange = (e) => {
    const { name, value, type, checked } = e.target;
    setError("");
    setFormData((prev) => ({
      ...prev,
      [name]: type === "checkbox" ? checked : value,
    }));
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setError("");

    if (formData.password !== formData.confirmPassword) {
      setError("Passwords do not match");
      return;
    }

    if (!formData.agreed) {
      setError("You must agree to the Rules & Fair Play Policy");
      return;
    }

    setIsLoading(true);

    try {
      const response = await fetch(`${API_BASE_URL}/api/auth/register`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({
          username: formData.username,
          email: formData.email,
          password: formData.password,
        }),
      });

      const data = await response.json();

      if (response.ok) {
        const userToSave = {
          _id: data.user._id,
          username: data.user.username,
          email: data.user.email
        };
        // Default to remembering user for signups
        login(data.token, userToSave, true);

        onClose();
        navigate(redirectTo || "/dashboard", { replace: true });
      } else {
        setError(data.message || "Registration failed");
      }
    } catch (err) {
      setError("Network error. Please try again.");
    } finally {
      setIsLoading(false);
    }
  };

  return (
    <AnimatePresence>
      {isOpen && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4">
          <motion.div
            initial={{ opacity: 0 }}
            animate={{ opacity: 1 }}
            exit={{ opacity: 0 }}
            onClick={onClose}
            className="absolute inset-0 bg-slate-900/60 backdrop-blur-sm"
          />

          <motion.div
            initial={{ scale: 0.95, opacity: 0, y: 20 }}
            animate={{ scale: 1, opacity: 1, y: 0 }}
            exit={{ scale: 0.95, opacity: 0, y: 20 }}
            className="relative w-full max-w-md bg-white rounded-2xl shadow-2xl overflow-hidden z-10 border border-slate-200  max-h-[90vh] overflow-y-auto"
          >
            {/* Close Button */}
            <button
              onClick={onClose}
              className="absolute top-4 right-4 p-2 text-slate-400 hover:text-slate-600 hover:bg-slate-100 rounded-full transition-colors z-20"
            >
              <X size={20} />
            </button>

            <div className="p-8">
              <div className="text-center mb-6">
