          </motion.div>
        </div>
      )}
    </AnimatePresence>
  );
}

/**
 * ═══════════════════════════════════════════════════════════════════
 * TabSwitchWarningModal — Warning/DQ UI Component
 * ═══════════════════════════════════════════════════════════════════
 *
 * Displays warning modals when tab-switch violations are detected.
 * Visually escalates from warning → final warning → disqualification.
 *
 * Props:
 *   - show: boolean — whether to display the modal
 *   - warnings: number — current violation count
 *   - maxWarnings: number — max before DQ (3)
 *   - message: string — server-provided warning text
 *   - isDisqualified: boolean — has the player been DQ'd
 *   - onDismiss: () => void — callback to close (not available when DQ'd)
 * ═══════════════════════════════════════════════════════════════════
 */

import React, { useEffect, useRef } from 'react';
import { AlertTriangle, XCircle, ShieldAlert, ShieldX } from 'lucide-react';

export default function TabSwitchWarningModal({
  show,
  warnings,
  maxWarnings,
  message,
  isDisqualified,
  onDismiss,
}) {
  const audioRef = useRef(null);

  // Play alert sound on modal show
  useEffect(() => {
    if (!show) return;

    try {
      const ctx = new (window.AudioContext || window.webkitAudioContext)();
      const osc = ctx.createOscillator();
      const gain = ctx.createGain();
      osc.connect(gain);
      gain.connect(ctx.destination);

      if (isDisqualified) {
        // Low, ominous tone for DQ
        osc.frequency.value = 200;
        gain.gain.value = 0.3;
        osc.start();
        osc.stop(ctx.currentTime + 0.8);
      } else if (warnings >= maxWarnings - 1) {
        // Urgent double-beep for final warning
        osc.frequency.value = 800;
        gain.gain.value = 0.2;
        osc.start();
        osc.stop(ctx.currentTime + 0.15);
        setTimeout(() => {
          const osc2 = ctx.createOscillator();
          const gain2 = ctx.createGain();
          osc2.connect(gain2);
          gain2.connect(ctx.destination);
          osc2.frequency.value = 1000;
          gain2.gain.value = 0.2;
          osc2.start();
          osc2.stop(ctx.currentTime + 0.15);
        }, 200);
      } else {
        // Single warning beep
        osc.frequency.value = 600;
        gain.gain.value = 0.15;
        osc.start();
        osc.stop(ctx.currentTime + 0.2);
      }
    } catch (e) {
      // AudioContext not available — fail silently
    }
  }, [show, warnings, isDisqualified, maxWarnings]);

  if (!show) return null;

  // ── Visual escalation based on severity ──
  const isFinalWarning = warnings >= maxWarnings - 1 && !isDisqualified;

  const bgColor = isDisqualified
    ? 'from-red-950 to-red-900'
    : isFinalWarning
      ? 'from-orange-950 to-red-950'
      : 'from-yellow-950 to-orange-950';

  const borderColor = isDisqualified
    ? 'border-red-500'
    : isFinalWarning
      ? 'border-orange-500'
      : 'border-yellow-500';

  const iconColor = isDisqualified
    ? 'text-red-400'
    : isFinalWarning
      ? 'text-orange-400'
      : 'text-yellow-400';

  const Icon = isDisqualified ? ShieldX : isFinalWarning ? ShieldAlert : AlertTriangle;

  const title = isDisqualified
    ? 'DISQUALIFIED'
    : isFinalWarning
      ? '⚠️ FINAL WARNING'
      : '⚠️ TAB SWITCH DETECTED';

  return (
    <div
      className="fixed inset-0 z-[9999] flex items-center justify-center"
      style={{ pointerEvents: 'auto' }}
    >
      {/* Backdrop */}
      <div
        className={`absolute inset-0 transition-all duration-300 ${
          isDisqualified
            ? 'bg-red-950/90 backdrop-blur-xl'
            : 'bg-black/70 backdrop-blur-md'
        }`}
      />

      {/* Modal */}
      <div
        className={`
          relative max-w-md w-full mx-4 rounded-2xl border-2 ${borderColor}
          bg-gradient-to-b ${bgColor} shadow-2xl overflow-hidden
          animate-[tabswitch-bounce_0.4s_ease-out]
        `}
      >
        {/* Pulsing border glow */}
        <div
          className={`absolute inset-0 rounded-2xl opacity-30 ${
            isDisqualified ? 'animate-pulse' : ''
          }`}
          style={{
            boxShadow: isDisqualified
              ? '0 0 60px rgba(239, 68, 68, 0.5), inset 0 0 60px rgba(239, 68, 68, 0.1)'
              : isFinalWarning
                ? '0 0 40px rgba(249, 115, 22, 0.4)'
                : '0 0 30px rgba(234, 179, 8, 0.3)',
          }}
        />

        {/* Content */}
        <div className="relative p-8 text-center">
          {/* Icon */}
          <div className={`mx-auto mb-5 ${isDisqualified ? 'animate-bounce' : ''}`}>
            <div
              className={`
                w-20 h-20 mx-auto rounded-2xl rotate-12 flex items-center justify-center
                ${isDisqualified
                  ? 'bg-red-500/20 border-2 border-red-500/50'
                  : isFinalWarning
                    ? 'bg-orange-500/20 border-2 border-orange-500/50'
                    : 'bg-yellow-500/20 border-2 border-yellow-500/50'
                }
              `}
            >
              <div className="-rotate-12">
                <Icon size={40} className={iconColor} />
              </div>
            </div>
          </div>

          {/* Title */}
          <h2
            className={`text-2xl font-black tracking-tight mb-3 ${
              isDisqualified ? 'text-red-400' : isFinalWarning ? 'text-orange-400' : 'text-yellow-400'
            }`}
          >
            {title}
          </h2>

          {/* Message */}
          <p className="text-slate-300 text-sm font-medium mb-6 leading-relaxed max-w-xs mx-auto">
            {message || 'Tab switching is not allowed during BLIND coding mode.'}
          </p>

          {/* Warning Counter */}
          <div className="mb-6">
            <div className="flex items-center justify-center gap-3">
              {Array.from({ length: maxWarnings }).map((_, i) => (
                <div
                  key={i}
                  className={`
                    w-10 h-10 rounded-xl flex items-center justify-center font-black text-sm
                    border-2 transition-all duration-300
                    ${i < warnings
                      ? isDisqualified
                        ? 'bg-red-500 border-red-400 text-white shadow-lg shadow-red-500/40'
                        : 'bg-orange-500 border-orange-400 text-white shadow-lg shadow-orange-500/40'
                      : 'bg-slate-800/50 border-slate-700 text-slate-600'
                    }
                  `}
                >
                  {i < warnings ? <XCircle size={18} /> : i + 1}
                </div>
              ))}
            </div>
            <p className="text-[11px] font-bold text-slate-500 mt-3 uppercase tracking-wider">
              Violations: {warnings} / {maxWarnings}
            </p>
          </div>

          {/* Action buttons */}
          {isDisqualified ? (
            <div className="space-y-3">
              <p className="text-red-400/80 text-xs font-bold uppercase tracking-widest animate-pulse">
                You have been removed from this competition
              </p>
              <button
                onClick={() => window.location.href = '/dashboard'}
                className="w-full py-3 bg-red-600 hover:bg-red-700 text-white font-bold rounded-xl transition-all text-sm uppercase tracking-wider"
              >
                Return to Dashboard
              </button>
            </div>
          ) : (
            <button
              onClick={onDismiss}
              className={`
                w-full py-3 font-bold rounded-xl transition-all text-sm uppercase tracking-wider
                ${isFinalWarning
                  ? 'bg-orange-600 hover:bg-orange-700 text-white'
                  : 'bg-yellow-600 hover:bg-yellow-700 text-white'
                }
              `}
            >
              {isFinalWarning ? 'I Understand — This is My Last Chance' : 'Continue Coding'}
            </button>
          )}
        </div>
      </div>

      {/* CSS Animation */}
      <style>{`
        @keyframes tabswitch-bounce {
          0% { transform: scale(0.8) translateY(20px); opacity: 0; }
          60% { transform: scale(1.03) translateY(-5px); opacity: 1; }
          100% { transform: scale(1) translateY(0); opacity: 1; }
        }
      `}</style>
    </div>
  );
}

import { createContext, useContext, useEffect, useState } from 'react';

const ThemeContext = createContext();

export const ThemeProvider = ({ children }) => {
    const [theme, setTheme] = useState(() => {
        const savedTheme = localStorage.getItem('theme');
        return savedTheme || 'light';
    });

    useEffect(() => {
        const root = window.document.documentElement;
        if (theme === 'dark') {
            root.classList.add('dark');
        } else {
            root.classList.remove('dark');
        }
        localStorage.setItem('theme', theme);
    }, [theme]);

    const toggleTheme = () => {
        setTheme((prev) => (prev === 'light' ? 'dark' : 'light'));
    };

    return (
        <ThemeContext.Provider value={{ theme, toggleTheme }}>
            {children}
        </ThemeContext.Provider>
    );
};

export const useTheme = () => {
    const context = useContext(ThemeContext);
    if (context === undefined) {
        throw new Error('useTheme must be used within a ThemeProvider');
    }
    return context;
};

import React, { useState, useEffect } from 'react';
import { useNavigate, useParams, useLocation } from 'react-router-dom';
import Editor from '@monaco-editor/react';
import {
    Swords,
    LogOut,
    Play,
    Terminal as TerminalIcon,
    Clock,
    Activity,
    Check,
    User,
    Sun,
    Moon
} from 'lucide-react';
import { getSocket, initiateSocketConnection } from '../services/socket';
import { API_BASE_URL } from '../config/api';
import { useTheme } from '../context/ThemeContext';

export default function BattleArenaPage() {
    const navigate = useNavigate();
    const { roomId } = useParams();
    const location = useLocation();
    const { theme, toggleTheme } = useTheme();
    const [user, setUser] = useState(() => {
        const savedUser = localStorage.getItem('user');
        return savedUser ? JSON.parse(savedUser) : null;
    });
    const [opponent, setOpponent] = useState({ username: 'Opponent', status: 'Thinking...' });
    const [problem, setProblem] = useState(null);
    const [loading, setLoading] = useState(true);
    const [code, setCode] = useState('// Write your solution here\n');
    const [output, setOutput] = useState('');
    const [isRunning, setIsRunning] = useState(false);
    const [gameStatus, setGameStatus] = useState('active'); // active, won, lost, timeout
    const [timeLeft, setTimeLeft] = useState(60);
    const [language, setLanguage] = useState('javascript');
    const [opponentActivity, setOpponentActivity] = useState('');
    const [problemId, setProblemId] = useState(null);



    const languages = [
        { id: 'javascript', name: 'JavaScript', version: 'v18.0' },
        { id: 'python', name: 'Python', version: 'v3.10' },
        { id: 'cpp', name: 'C++', version: 'GCC 11' },
        { id: 'c', name: 'C', version: 'GCC 11' },
        { id: 'java', name: 'Java', version: 'JDK 17' }
    ];


    // Clear opponent activity after 3 seconds
    useEffect(() => {
        if (opponentActivity) {
            const timer = setTimeout(() => {
                setOpponentActivity('');
            }, 3000);
            return () => clearTimeout(timer);
        }
    }, [opponentActivity]);

    // Emit code updates for replays and indicators
    useEffect(() => {
        const socket = getSocket();
        if (socket && code) {
            socket.emit('battle:typing', { roomId });

            // Debounce actual content update to avoid flood
            const timer = setTimeout(() => {
                socket.emit('battle:codeUpdate', { roomId, code });
            }, 1000);

            return () => clearTimeout(timer);
        }
    }, [code, roomId]);

    useEffect(() => {
        try {
            const token = localStorage.getItem('token');
            let socket = getSocket();

            // Check if missing or disconnected
            if (!socket || !socket.connected) {
                if (token) {
                    console.log("Socket missing or disconnected, (re)connecting...");
                    initiateSocketConnection(token);
                    socket = getSocket();
                } else {
                    navigate('/login');
                    return;
                }
            }

            // Restore opponent name if we came from Lobby
            if (location.state?.opponent) {
                setOpponent({ username: location.state.opponent.username, status: 'Connected' });
            }

            const storedUser = JSON.parse(localStorage.getItem('user'));
            const currentUser = user || storedUser;

            // Fallback for missing username
            if (currentUser && !currentUser.username && currentUser.email) {
                currentUser.username = currentUser.email.split('@')[0];
                localStorage.setItem('user', JSON.stringify(currentUser));
                if (!user) setUser(currentUser);
            }

            console.log("BATTLE_ARENA: Identified user as:", currentUser?.username);

            if (socket) {
                console.log(`BATTLE_ARENA: Attempting to join room [${roomId}] as [${currentUser?.username}]`);
                socket.emit('join_room', roomId, { username: currentUser?.username });

                socket.on('battle:opponentInfo', (opponentData) => {
                    console.log("Opponent info received:", opponentData);
                    setOpponent({ username: opponentData.username, status: 'Connected' });
                });

                socket.on('battle:startTimer', ({ duration }) => {
                    console.log("Timer started:", duration);
                    setTimeLeft(duration);
                });

                socket.on('battle:timerUpdate', ({ timeLeft, problemId: pId }) => {
                    console.log("Timer update received:", timeLeft, pId);
                    setTimeLeft(timeLeft);
                    if (pId && !problemId) setProblemId(pId);
                });


                socket.on('battle:end', ({ reason }) => {
                    console.log("Battle ended:", reason);
                    setGameStatus('timeout');
                    setIsRunning(false);
                    setOutput("> BATTLE ENDED: Time Limit Reached (timeout).");
                });

                socket.on('battle:error', ({ message }) => {
                    console.error("Battle error:", message);
                    alert(message);
                    navigate('/dashboard');
                });

                socket.on('battle:result', ({ winnerId, winnerName, reason }) => {
                    console.log("Battle Result Received:", winnerId, winnerName);
                    if (socket.id === winnerId) {
                        setGameStatus('won');
                    } else {
                        setGameStatus('lost');
                    }
                    setIsRunning(false);
                });

                // Opponent Activity Listeners
                socket.on('battle:opponentTyping', () => {
                    setOpponentActivity('Typing...');
                });

                socket.on('battle:opponentRunningTests', () => {
                    setOpponentActivity('Running tests...');
                });

                socket.on('battle:opponentAttempting', () => {
                    setOpponentActivity('Submitted solution');
                });

                socket.on('battle:executionResult', (result) => {
                    setIsRunning(false);
                    if (result.success) {
                        setOutput(`PASSED: ${result.logs}\nExecution Time: ${result.executionTime}ms`);
                    } else {
                        setOutput(`FAILED: ${result.error || result.logs}\nExecution Time: ${result.executionTime}ms`);
                    }
                });

                // Cleanup listeners on unmount
                return () => {
                    socket.off('battle:opponentInfo');
                    socket.off('battle:startTimer');
                    socket.off('battle:timerUpdate');
                    socket.off('battle:end');
                    socket.off('battle:error');
                    socket.off('battle:result');
                    socket.off('battle:opponentTyping');
                    socket.off('battle:opponentRunningTests');
                    socket.off('battle:opponentAttempting');
                    socket.off('battle:executionResult');
                };
            }
        } catch (err) {
            console.error("CRITICAL ERROR IN BATTLE_ARENA_EFFECT:", err);
        }
    }, [roomId, location.state, problemId]);

    useEffect(() => {
        const fetchProblem = async () => {
            if (!problemId) return;
            setLoading(true);
            try {
                const response = await fetch(`${API_BASE_URL}/api/problems/${problemId}`);
                const data = await response.json();
                setProblem(data);

                // Set initial code from template if available
                if (data.templates && Array.isArray(data.templates)) {
                    const template = data.templates.find(t => t.language === language);
                    if (template) setCode(template.code);
