                        </div>
                        <div className="flex flex-col items-start">
                            <div className="flex items-center gap-3 px-4 py-1.5 bg-slate-50 dark:bg-slate-800 rounded-full border border-slate-200 dark:border-slate-700 relative">
                                <span className="text-sm font-bold text-slate-700 dark:text-slate-300">{opponent.username}</span>
                                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">OPP</span>
                            </div>
                            <span className="text-[10px] font-black text-red-600 dark:text-red-400 uppercase italic ml-4">{opponent.rank || 'Bronze'}</span>
                        </div>

                        {/* Opponent Activity Indicator Tag */}
                        {opponentActivity && (
                            <div className="absolute -bottom-6 right-0 whitespace-nowrap animate-bounce">
                                <span className="text-[10px] font-bold text-blue-600 dark:text-blue-400 bg-blue-50 dark:bg-blue-900/40 px-2 py-0.5 rounded border border-blue-100 dark:border-blue-800 shadow-sm">
                                    {opponentActivity}
                                </span>
                            </div>
                        )}
                    </div>
                </div>

                {/* CENTRAL TIMER - Light/Dark Mode High Contrast */}
                <div className="absolute left-1/2 -translate-x-1/2">
                    <div className={`px-8 py-2 rounded-xl border-2 font-mono font-black text-2xl flex items-center gap-4 transition-all duration-500 shadow-sm ${timeLeft <= 30
                        ? 'bg-red-50 dark:bg-red-950 border-red-500 text-red-600 dark:text-red-400 scale-105'
                        : 'bg-white dark:bg-slate-900 border-slate-200 dark:border-slate-800 text-slate-900 dark:text-white'
                        }`}>
                        <Clock size={20} className={timeLeft <= 30 ? 'animate-pulse text-red-500' : 'text-blue-500'} />
                        <span className="tabular-nums tracking-tight">
                            {Math.floor(timeLeft / 60)}:{(timeLeft % 60).toString().padStart(2, '0')}
                        </span>
                    </div>
                </div>

                <div className="flex items-center gap-4">
                    <button
                        onClick={toggleTheme}
                        className="p-2 rounded-lg bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-400 hover:bg-slate-200 dark:hover:bg-slate-700 transition-all border border-slate-200 dark:border-slate-700"
                        aria-label="Toggle Theme"
                    >
                        {theme === 'light' ? <Moon size={18} /> : <Sun size={18} />}
                    </button>
                    <button
                        onClick={() => navigate('/dashboard')}
                        className="px-5 py-2 text-xs font-bold text-slate-600 dark:text-slate-400 hover:text-red-600 dark:hover:text-red-400 bg-white dark:bg-slate-900 hover:bg-red-50 dark:hover:bg-red-950/30 border border-slate-200 dark:border-slate-700 hover:border-red-200 dark:hover:border-red-900/50 rounded-lg transition-all uppercase flex items-center gap-2"
                    >
                        <LogOut size={14} />
                        <span>Withdraw</span>
                    </button>
                </div>
            </header>

            {/* Main Application Area */}
            <main className="flex-1 flex overflow-hidden">

                {/* Left Side: Problem Card - Clean Light/Dark */}
                <div className="w-[42%] bg-[#F1F5F9]/30 dark:bg-slate-900/30 p-8 overflow-y-auto border-r border-slate-200 dark:border-slate-800 custom-scrollbar transition-colors duration-300">
                    <div className="space-y-8">
                        {loading ? (
                            <div className="flex flex-col items-center justify-center h-64 space-y-4">
                                <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-blue-600"></div>
                                <p className="text-slate-500 font-mono text-xs">SYNCHRONIZING_PROBLEM...</p>
                            </div>
                        ) : problem ? (
                            <>
                                <div>
                                    <div className="flex items-center gap-3 mb-2">
                                        <span className={`px-2.5 py-1 rounded text-[10px] font-black uppercase tracking-wider border ${problem.difficulty === 'Easy' ? 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-400 border-green-200 dark:border-green-900/50' :
                                            problem.difficulty === 'Medium' ? 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-400 border-yellow-200 dark:border-yellow-900/50' :
                                                'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-400 border-red-200 dark:border-red-900/50'
                                            }`}>
                                            Rank_{problem.difficulty}
                                        </span>
                                        <span className="text-[10px] text-slate-400 dark:text-slate-500 uppercase font-black tracking-widest flex items-center gap-1.5">
                                            <Activity size={14} className="text-blue-500 dark:text-blue-400" /> {problem.xpReward} XP Reward
                                        </span>
                                    </div>
                                    <h2 className="text-3xl font-black text-slate-900 dark:text-white tracking-tight leading-tight transition-colors duration-300">{problem.title}</h2>
                                </div>

                                <div className="bg-white dark:bg-slate-900 border border-slate-200 dark:border-slate-800 rounded-2xl p-6 shadow-sm space-y-6 transition-colors duration-300">
                                    <div className="text-base leading-relaxed text-slate-600 dark:text-slate-400 space-y-4 font-medium prose prose-slate dark:prose-invert max-w-none">
                                        <div dangerouslySetInnerHTML={{ __html: problem.description }} />
                                    </div>

                                    {problem.examples && problem.examples.length > 0 && (
                                        <div className="bg-slate-50 dark:bg-slate-800/50 rounded-xl p-5 border border-slate-200/60 dark:border-slate-700/60 mt-6">
                                            <div className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase mb-3 tracking-widest">Example Case 01</div>
                                            <pre className="text-sm font-mono text-slate-700 dark:text-slate-300 bg-white/50 dark:bg-slate-950/50 p-3 rounded border border-slate-200/40 dark:border-slate-800/40">
                                                Input: {problem.examples[0].input}{"\n"}
                                                Output: {problem.examples[0].output}{"\n"}
                                                {problem.examples[0].explanation && `Explanation: ${problem.examples[0].explanation}`}
                                            </pre>
                                        </div>
                                    )}
                                </div>
                            </>
                        ) : (
                            <div className="text-center py-12">
                                <p className="text-slate-500 italic">No problem data found for ID: {problemId}</p>
                            </div>
                        )}

                        <div className="p-4 bg-orange-50 dark:bg-orange-900/20 rounded-lg border border-orange-100 dark:border-orange-900/30 text-[11px] text-orange-700 dark:text-orange-400 font-bold uppercase tracking-wider flex items-center gap-3 mt-6">
                            <div className="w-1.5 h-1.5 rounded-full bg-orange-500 animate-ping"></div>
                            Competitive Rule: Manual test execution is limited.
                        </div>
                    </div>
                </div>


                {/* Right Side: Interactive Zone */}
                <div className="flex-1 flex flex-col bg-[#1E1E1E]" >
                    {/* Tab Bar - Light/Dark Style */}
                    <div className="h-12 bg-white dark:bg-slate-900 border-b border-slate-200 dark:border-slate-800 flex items-center justify-between px-4 transition-colors duration-300" >
                        <div className="flex items-center gap-4 h-full">
                            <div className="flex items-center gap-2">
                                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Language:</span>
                                <select
                                    value={language}
                                    onChange={(e) => {
                                        const newLang = e.target.value;
                                        setLanguage(newLang);

                                        // Try to find template in problem data
                                        if (problem?.templates && Array.isArray(problem.templates)) {
                                            const template = problem.templates.find(t => t.language === newLang);
                                            if (template) {
                                                setCode(template.code);
                                                return;
                                            }
                                        }

                                        // Fallback templates
                                        if (newLang === 'python') setCode('# Write your solution here\n');
                                        else if (newLang === 'cpp' || newLang === 'c') setCode('#include <stdio.h>\n\nint main() {\n    return 0;\n}');
                                        else if (newLang === 'java') setCode('public class Solution {\n    public static void main(String[] args) {\n    }\n}');
                                        else setCode('// Write your solution here\nfunction solve(input) {\n}');
                                    }}

                                    className="bg-slate-50 dark:bg-slate-800 text-slate-700 dark:text-slate-300 text-[10px] font-bold py-1 px-2 rounded border border-slate-200 dark:border-slate-700 focus:outline-none"
                                >
                                    {languages.map(lang => (
                                        <option key={lang.id} value={lang.id}>{lang.name}</option>
                                    ))}
                                </select>
                            </div>
                        </div>
                        <div className="text-[10px] font-black text-slate-400 dark:text-slate-500 tracking-widest uppercase">Environment: Docker_Sandbox</div>
                    </div>


                    <div className="flex-1 relative overflow-hidden">
                        <Editor
                            height="100%"
                            defaultLanguage="javascript"
                            language={language === 'cpp' || language === 'c' ? 'cpp' : language}
                            value={code}

                            onChange={(value) => {
                                setCode(value);
                                const socket = getSocket();
                                if (socket && gameStatus === 'active') {
                                    socket.emit('battle:typing', { roomId });
                                }
                            }}
                            theme={theme === 'dark' ? 'vs-dark' : 'light'}
                            options={{
                                minimap: { enabled: false },
                                fontSize: 13,
                                fontFamily: "'JetBrains Mono', monospace",
                                lineNumbers: 'on',
                                padding: { top: 20 },
                                automaticLayout: true,
                                scrollBeyondLastLine: false,
                                readOnly: gameStatus !== 'active'
                            }}
                        />
                    </div>

                    {/* Pro Console Footer - Light/Dark Terminal */}
                    <div className="h-60 bg-white dark:bg-slate-900 border-t border-slate-200 dark:border-slate-800 flex flex-col z-40 transition-colors duration-300">
                        <div className="h-12 bg-white dark:bg-slate-900 px-6 flex items-center justify-between border-b border-slate-100 dark:border-slate-800">
                            <div className="flex items-center gap-3">
                                <span className="text-[10px] font-black text-slate-400 dark:text-slate-500 uppercase tracking-widest">Execution_Logs</span>
                            </div>
                            <div className="flex gap-3">
                                <button
                                    onClick={handleRunCode}
                                    disabled={isRunning || gameStatus !== 'active'}
                                    className="flex items-center gap-2 px-4 py-2 bg-slate-100 dark:bg-slate-800 hover:bg-slate-200 dark:hover:bg-slate-700 text-slate-600 dark:text-slate-400 text-[10px] font-black uppercase rounded-lg transition-all disabled:opacity-30 border border-transparent dark:border-slate-700"
                                >
                                    <Play size={14} /> Run_Tests
                                </button>
                                <button
                                    onClick={handleSubmit}
                                    disabled={isRunning || gameStatus !== 'active'}
                                    className="flex items-center gap-2 px-6 py-2 bg-blue-600 hover:bg-blue-700 text-white text-[10px] font-black uppercase rounded-lg shadow-md hover:translate-y-[-1px] transition-all disabled:opacity-30"
                                >
                                    <Check size={14} /> Submit_Ready
                                </button>
                            </div>
                        </div>
                        <div className="flex-1 p-6 font-mono text-sm overflow-y-auto bg-slate-900 dark:bg-slate-950 text-slate-300 dark:text-white transition-colors duration-300">
                            {isRunning ? (
                                <div className="space-y-3">
                                    <div className="text-blue-400 animate-pulse font-black tracking-widest text-xs uppercase">Connecting to runtime...</div>
                                    <div className="w-48 h-1 bg-slate-800 rounded-full overflow-hidden">
                                        <div className="h-full bg-blue-500 animate-[loading_1.5s_infinite]"></div>
                                    </div>
                                </div>
                            ) : (
                                <pre className="whitespace-pre-wrap leading-relaxed opacity-90">{output || "> STANDBY: Awaiting input..."}</pre>
                            )}
                        </div>
                    </div>
                </div>
            </main>

            {/* Battle Result Overlay - Clean Light/Dark Accent */}
            {(gameStatus === 'won' || gameStatus === 'lost' || gameStatus === 'timeout') && (
                <div className="fixed inset-0 z-[100] flex items-center justify-center bg-slate-930/80 dark:bg-slate-950/90 backdrop-blur-md animate-in fade-in duration-500">
                    <div className="bg-white dark:bg-slate-900 p-8 md:p-10 rounded-[2rem] max-w-2xl w-full mx-4 shadow-[0_25px_50px_-12px_rgba(0,0,0,0.5)] border border-slate-200 dark:border-slate-800 transform animate-in zoom-in-95 duration-500 overflow-hidden relative">
                        
                        {/* Decorative background elements */}
                        {gameStatus === 'won' && <div className="absolute -top-32 -right-32 w-64 h-64 bg-green-500/10 dark:bg-green-500/20 rounded-full blur-3xl"></div>}
                        {gameStatus === 'lost' && <div className="absolute -top-32 -right-32 w-64 h-64 bg-red-500/10 dark:bg-red-500/20 rounded-full blur-3xl"></div>}
                        
                        <div className="flex flex-col md:flex-row gap-8 items-center md:items-start relative z-10">
                            
                            {/* Left Column: Status */}
                            <div className="flex-1 flex flex-col items-center text-center">
                                <div className={`w-24 h-24 mb-6 rounded-3xl rotate-12 flex items-center justify-center border-4 shadow-xl ${gameStatus === 'won' ? 'bg-green-50 text-green-500 border-green-100 dark:bg-green-900/30 dark:border-green-500/50' : 'bg-red-50 text-red-500 border-red-100 dark:bg-red-900/30 dark:border-red-500/50'}`}>
                                    <div className="-rotate-12 transform group-hover:scale-110 transition-transform">
                                        {gameStatus === 'won' ? <Check size={48} strokeWidth={3} /> : <Swords size={48} strokeWidth={3} />}
                                    </div>
                                </div>

                                <h2 className={`text-4xl md:text-5xl font-black font-sans mb-3 tracking-tighter uppercase ${gameStatus === 'won' ? 'text-green-600 dark:text-green-400' : gameStatus === 'lost' ? 'text-red-600 dark:text-red-400' : 'text-slate-500'}`}>
                                    {gameStatus === 'won' ? 'VICTORY' : gameStatus === 'lost' ? 'DEFEAT' : 'TIMEOUT'}
                                </h2>
                                <p className="text-slate-500 dark:text-slate-400 mb-8 font-bold tracking-tight text-sm uppercase">
                                    {gameStatus === 'won' ? 'Algorithm Execution Superior' : gameStatus === 'lost' ? 'Logic Compromised' : 'Time limit exceeded'}
                                </p>

                                <div className="space-y-3 w-full">
                                    <button
                                        onClick={() => navigate('/dashboard')}
                                        className="w-full py-3.5 bg-blue-600 hover:bg-blue-700 text-white font-black uppercase tracking-widest rounded-xl transition-all shadow-lg shadow-blue-500/30 hover:-translate-y-1 text-sm flex items-center justify-center gap-2"
                                    >
                                        <Activity size={16} /> Dashboard
                                    </button>
                                    <button
                                        onClick={() => navigate('/lobby')}
                                        className="w-full py-3.5 bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-slate-200 dark:hover:bg-slate-700 font-bold uppercase tracking-widest rounded-xl transition-all text-sm border border-transparent dark:border-slate-700"
                                    >
                                        Seek New Match
                                    </button>
                                </div>
                            </div>

                            {/* Right Column: AI Analysis */}
                            <div className="flex-1 w-full bg-slate-50 dark:bg-slate-950/50 rounded-2xl p-6 border border-slate-200 dark:border-slate-800 relative overflow-hidden">
                                <div className="flex items-center gap-2 mb-6 border-b border-slate-200 dark:border-slate-800 pb-3">
                                    <div className="p-1.5 bg-blue-100 dark:bg-blue-900/50 text-blue-600 dark:text-blue-400 rounded-lg">
                                        <TerminalIcon size={16} />
                                    </div>
                                    <h3 className="font-bold text-slate-900 dark:text-white font-mono text-sm tracking-tight">AI_POST_MATCH_ANALYSIS</h3>
                                    <div className="ml-auto w-2 h-2 bg-green-500 rounded-full animate-pulse"></div>
                                </div>

                                <div className="space-y-5">
                                    <div className="flex justify-between items-center bg-white dark:bg-slate-900 p-3 rounded-lg border border-slate-100 dark:border-slate-800 shadow-sm">
                                        <span className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Time Complexity</span>
                                        <span className="font-mono font-black text-blue-600 dark:text-blue-400 text-sm bg-blue-50 dark:bg-blue-900/20 px-2 py-1 rounded">O(N)</span>
                                    </div>
                                    <div className="flex justify-between items-center bg-white dark:bg-slate-900 p-3 rounded-lg border border-slate-100 dark:border-slate-800 shadow-sm">
                                        <span className="text-xs font-bold text-slate-500 dark:text-slate-400 uppercase tracking-wider">Space Complexity</span>
                                        <span className="font-mono font-black text-green-600 dark:text-green-400 text-sm bg-green-50 dark:bg-green-900/20 px-2 py-1 rounded">O(1)</span>
                                    </div>
                                    
                                    <div className="mt-4 pt-4 border-t border-slate-200 dark:border-slate-800">
                                        <h4 className="text-[10px] uppercase tracking-widest font-black text-slate-400 mb-2">Code Quality Insights</h4>
                                        <div className="bg-slate-100 dark:bg-slate-800/80 p-3 rounded-lg text-xs font-mono text-slate-600 dark:text-slate-400 leading-relaxed border border-slate-200 dark:border-slate-700 border-l-2 border-l-blue-500">
                                            {gameStatus === 'won' 
                                                ? "> Exceptional logic. No memory leaks detected. Variable naming is concise and readable. Execution time was optimal for the given constraints."
                                                : "> Optimization required. Consider reducing nested loops. The opponent utilized a more efficient data structure."}
                                        </div>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
}

import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import {
    Swords,
    LogOut,
    Plus,
    Users,
    Zap,
    Clock,
    Terminal as TerminalIcon,
    Loader,
    Search,
    UserPlus,
    Check,
    X,
    Bell,
    UserCheck,
    Send
} from 'lucide-react';

import { initiateSocketConnection, joinQueue, subscribeToMatchFound, disconnectSocket, getSocket, joinPersonalRoom, challengeFriend, respondToChallenge } from '../services/socket';
import { API_BASE_URL } from '../config/api';

export default function BattleLobbyPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState(() => {
        const savedUser = localStorage.getItem('user');
        return savedUser ? JSON.parse(savedUser) : null;
    });
    const [isMatchmaking, setIsMatchmaking] = useState(false);
    const [matchmakingTime, setMatchmakingTime] = useState(0);
    const [showLogoutConfirm, setShowLogoutConfirm] = useState(false);
    
    // Friend System State
    const [friends, setFriends] = useState([]);
    const [friendRequests, setFriendRequests] = useState([]);
    const [searchResults, setSearchResults] = useState([]);
    const [searchQuery, setSearchQuery] = useState('');
    const [isSearching, setIsSearching] = useState(false);
    const [activeTab, setActiveTab] = useState('friends'); // 'friends' or 'battles'
    const [incomingChallenge, setIncomingChallenge] = useState(null);
    const [toast, setToast] = useState(null); // { message, type: 'info' | 'error' | 'success' }

    useEffect(() => {
        const token = localStorage.getItem('token');
        const storedUser = localStorage.getItem('user');

        if (!token || !storedUser) {
            navigate('/login');
            return;
        }

        if (token && !getSocket()) {
            console.log("Initializing socket in lobby...");
            initiateSocketConnection(token);
        }

        const socket = getSocket();
        if (socket && storedUser) {
            const userId = JSON.parse(storedUser)._id;
            joinPersonalRoom(userId);

            socket.on("challenge:received", (data) => {
                console.log("Challenge received:", data);
                setIncomingChallenge(data);
            });

            socket.on("challenge:rejected", ({ friendName }) => {
                setToast({ message: `${friendName} rejected your challenge.`, type: 'error' });
                setTimeout(() => setToast(null), 3000);
            });
        }

        // Listen for matches
        subscribeToMatchFound((data) => {
            console.log("Match found event received:", data);
            setIsMatchmaking(false);
            navigate(`/battle/${data.roomId}`, { state: { opponent: data.opponent } });
        });

        // Fetch Initial Friends
        fetchFriends();
        fetchFriendRequests();

        return () => {
             if (socket) {
                socket.off("challenge:received");
                socket.off("challenge:rejected");
             }
        };
    }, []);

    const fetchFriends = async () => {
        try {
            const token = localStorage.getItem('token');
            const res = await fetch(`${API_BASE_URL}/api/users/friends`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            setFriends(data);
        } catch (error) {
            console.error("Failed to fetch friends", error);
        }
    };

    const fetchFriendRequests = async () => {
        try {
            const token = localStorage.getItem('token');
            const res = await fetch(`${API_BASE_URL}/api/users/friend-requests`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            setFriendRequests(data);
        } catch (error) {
            console.error("Failed to fetch friend requests", error);
        }
    };

    const handleSearch = async (e) => {
        const query = e.target.value;
        setSearchQuery(query);
        if (query.length < 2) {
            setSearchResults([]);
            return;
        }

        setIsSearching(true);
        try {
            const token = localStorage.getItem('token');
            const res = await fetch(`${API_BASE_URL}/api/users/search?username=${query}`, {
                headers: { 'Authorization': `Bearer ${token}` }
            });
            const data = await res.json();
            setSearchResults(data);
        } catch (error) {
            console.error("Search failed", error);
        } finally {
            setIsSearching(false);
        }
    };

    const sendFriendRequest = async (targetUserId) => {
        try {
            const token = localStorage.getItem('token');
            const res = await fetch(`${API_BASE_URL}/api/users/friend-request`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ targetUserId })
            });
            const data = await res.json();
            if (data.success) {
                alert("Request sent!");
                setSearchResults(prev => prev.filter(u => u._id !== targetUserId));
            } else {
                alert(data.message);
            }
        } catch (error) {
            console.error("Friend request failed", error);
        }
    };

    const respondToRequest = async (requestId, action) => {
        try {
            const token = localStorage.getItem('token');
            const res = await fetch(`${API_BASE_URL}/api/users/respond-request`, {
                method: 'POST',
                headers: { 
                    'Authorization': `Bearer ${token}`,
                    'Content-Type': 'application/json'
                },
                body: JSON.stringify({ requestId, action })
            });
            if (res.ok) {
                fetchFriends();
                fetchFriendRequests();
            }
        } catch (error) {
            console.error("Response failed", error);
        }
    };

    const handleChallenge = (friend) => {
        challengeFriend(friend._id, user);
        setToast({ message: `Challenge sent to ${friend.username}! Waiting for response...`, type: 'info' });
        setTimeout(() => setToast(null), 5000);
    };

    const handleIncomingResponse = (accepted) => {
        respondToChallenge(incomingChallenge.challenger._id, accepted, user);
        setIncomingChallenge(null);
    };

    useEffect(() => {
        let interval;
        if (isMatchmaking) {
            interval = setInterval(() => {
                setMatchmakingTime(prev => prev + 1);
            }, 1000);
        } else {
            setMatchmakingTime(0);
        }
        return () => clearInterval(interval);
    }, [isMatchmaking]);

    const handleLogout = () => {
        localStorage.removeItem('token');
        localStorage.removeItem('user');
        navigate('/login');
    };

    const startMatchmaking = () => {
        // Always try to get fresh data from localStorage to avoid state staleness
        const storedData = localStorage.getItem('user');
        let currentUser = user;

        if (storedData) {
            currentUser = JSON.parse(storedData);
        }

        if (!currentUser) {
            console.error("No user data found in state or localStorage");
            alert("Session error. Please logout and login again.");
            return;
        }

        // Fallback for missing username
        if (!currentUser.username) {
            if (currentUser.email) {
                currentUser.username = currentUser.email.split('@')[0];
            } else {
                currentUser.username = `User_${Math.floor(Math.random() * 10000)}`;
            }
            // Update both state and storage
            setUser(currentUser);
            localStorage.setItem('user', JSON.stringify(currentUser));
        }

        console.log("Lobby: Starting matchmaking for:", currentUser.username);
        setIsMatchmaking(true);
        joinQueue(currentUser);
    };

    const cancelMatchmaking = () => {
        setIsMatchmaking(false);
        // Implement leave queue logic in socket service if needed
    };

    const formatTime = (seconds) => {
        const mins = Math.floor(seconds / 60);
        const secs = seconds % 60;
        return `${mins}:${secs.toString().padStart(2, '0')}`;
    };

    // Mock active battles
