                                        friends.map(friend => (
                                            <div key={friend._id} className="p-5 mb-4 rounded-2xl hover:bg-slate-50 dark:hover:bg-slate-800/80 border border-slate-100 dark:border-slate-800 transition-all group shadow-sm transition-colors">
                                                <div className="flex items-center justify-between mb-4">
                                                    <div className="flex items-center gap-3">
                                                        <div className="w-12 h-12 bg-slate-100 dark:bg-slate-800 rounded-2xl flex items-center justify-center text-slate-400 dark:text-slate-500 font-black border border-slate-200 dark:border-slate-700">
                                                            {friend.username.charAt(0).toUpperCase()}
                                                        </div>
                                                        <div>
                                                            <div className="font-black text-slate-900 dark:text-white transition-colors">{friend.username}</div>
                                                            <div className="text-[10px] font-bold text-blue-600 dark:text-blue-400 uppercase tracking-widest">{friend.rank}</div>
                                                        </div>
                                                    </div>
                                                    <div className="flex items-center gap-1.5 text-slate-400 dark:text-slate-500 text-xs font-bold transition-colors">
                                                        <Zap size={14} className="text-yellow-500" />
                                                        <span>{friend.wins} WINS</span>
                                                    </div>
