                                                <button
                                                    onClick={() => handleChallenge(friend)}
                                                    className="w-full py-3 bg-blue-600 text-white text-xs font-black rounded-xl hover:bg-blue-700 shadow-lg shadow-blue-500/20 transition-all flex items-center justify-center gap-2 transform active:scale-95"
                                                >
