}

import React, { useEffect, useState, useRef } from 'react';
import { useNavigate } from 'react-router-dom';
import Navbar from '../components/Navbar';
import {
    Swords,
    Trophy,
    Users,
    Code,
    Zap,
    Target,
    Activity,
    GitBranch,
    Terminal as TerminalIcon,
    Loader,
    Globe2,
    Flame,
    Clock,
    Award,
    TrendingUp,
    Star,
    Calendar,
    ChevronRight
} from 'lucide-react';
import { API_BASE_URL } from '../config/api';

export default function DashboardPage() {
    const navigate = useNavigate();
    const [user, setUser] = useState(() => {
        const savedUser = localStorage.getItem('user');
        return savedUser ? JSON.parse(savedUser) : null;
    });
    
    // Live Feed State
    const [liveLogs, setLiveLogs] = useState([]);
    const logsEndRef = useRef(null);
    const lastActivityId = useRef(null);
    
    // Competitive Presentation States
    const [platformStats, setPlatformStats] = useState({
        totalBattles: 0,
        leaders: [],
        trendingProblems: []
    });
    const [countdown, setCountdown] = useState(3600 * 24 * 3 + 3600 * 5 + 60 * 12 + 45); // Keep contest timer for aesthetic

    useEffect(() => {
        const token = localStorage.getItem('token');
        if (!token || !user) {
            navigate('/login');
            return;
        }

        const fetchUserData = async () => {
            try {
                const response = await fetch(`${API_BASE_URL}/api/users/profile/${user._id}`, {
                    headers: { 'Authorization': `Bearer ${token}` }
                });
                const result = await response.json();
                if (result.user) {
                    setUser(result.user);
                    localStorage.setItem('user', JSON.stringify(result.user));
                }
            } catch (error) {
                console.error("Failed to sync user data", error);
            }
        };

        fetchUserData();
    }, [navigate]);

    // Block back button — user must logout to leave dashboard
    useEffect(() => {
        // Push an extra entry so pressing back stays on dashboard
        window.history.pushState(null, '', window.location.href);

        const handlePopState = () => {
            window.history.pushState(null, '', window.location.href);
        };

        window.addEventListener('popstate', handlePopState);
        return () => {
            window.removeEventListener('popstate', handlePopState);
        };
    }, []);

    // Active Users & Countdown Timer
    useEffect(() => {
        const countdownInterval = setInterval(() => {
            setCountdown(prev => prev > 0 ? prev - 1 : 0);
        }, 1000);
        
        return () => {
            clearInterval(countdownInterval);
        };
    }, []);

    const formatCountdown = (seconds) => {
        const d = Math.floor(seconds / (3600*24));
        const h = Math.floor(seconds % (3600*24) / 3600).toString().padStart(2, '0');
        const m = Math.floor(seconds % 3600 / 60).toString().padStart(2, '0');
        const s = Math.floor(seconds % 60).toString().padStart(2, '0');
        return `${d}d ${h}h ${m}m ${s}s`;
    };

    // Real Platform Logs & Stats Fetcher
    useEffect(() => {
        if (!user) return;
        
        let initialLoad = true;
        let isChecking = false;

        const syncPlatformData = async () => {
            try {
                if (initialLoad) {
                    const [leaderboardRes, problemsRes] = await Promise.all([
                        fetch(`${API_BASE_URL}/api/leaderboard`),
                        fetch(`${API_BASE_URL}/api/problems?category=All`)
                    ]);
                    
                    const leadersData = await leaderboardRes.json();
                    const problemsData = await problemsRes.json();
                    
                    const totalPlayed = Array.isArray(leadersData) 
                        ? leadersData.reduce((sum, u) => sum + (u.battlesPlayed || 0), 0)
                        : 0;

                    setPlatformStats({
                        totalBattles: totalPlayed,
                        leaders: Array.isArray(leadersData) ? leadersData.slice(0, 3) : [],
                        trendingProblems: Array.isArray(problemsData) ? problemsData.slice(0, 3) : []
                    });
                }

                if (isChecking) return;
                isChecking = true;

                // Sync Recent Activity
                const actRes = await fetch(`${API_BASE_URL}/api/problems/activity`);
                const activities = await actRes.json();
                
                if (Array.isArray(activities) && activities.length > 0) {
                    const latestId = activities[0]._id;
                    
                    if (lastActivityId.current !== latestId) {
                        const newLogs = [];
                        
                        // Map activities to UI logs format
                        activities.reverse().forEach((act, i) => {
                            if (!initialLoad && lastActivityId.current && i < activities.length - 1) return; // Only process truly new logs on subseq ticks
  
                            let type = 'SUBMIT';
                            let color = 'text-cyan-500';
                            let msg = `User '${act.user?.username || 'Unknown'}' submitted ${act.status} for '${act.problem?.title || 'Unknown'}'.`;
                            
                            if (act.status === 'Accepted') {
                                type = 'SUCCESS';
                                color = 'text-green-500';
                                msg = `User '${act.user?.username}' successfully solved '${act.problem?.title}' in ${act.executionTime || 0}ms!`;
                            } else if (act.status === 'Wrong Answer' || act.status === 'Runtime Error') {
                                type = 'FAILED';
                                color = 'text-red-500';
                                msg = `User '${act.user?.username}' encountered ${act.status} on '${act.problem?.title}'.`;
                            }

                            newLogs.push({
                                id: act._id,
                                time: new Date(act.createdAt).toLocaleTimeString('en-US', {hour12: false}),
                                type, color, text: msg,
                                isNew: !initialLoad // Animate only if it's a fresh polling update
                            });
                        });
                        
                        setLiveLogs(prev => {
                            const updated = prev.map(l => ({ ...l, isNew: false }));
                            
                            // Merge ensuring uniqueness
                            const merged = [...updated];
                            newLogs.forEach(nLog => {
                                if (!merged.find(m => m.id === nLog.id)) {
                                    merged.push(nLog);
                                }
                            });
                            
                            return merged.slice(-15);
                        });
                        
                        lastActivityId.current = latestId;
                    }
                }
            } catch (err) {
                console.error("Failed syncing platform data:", err);
            } finally {
                isChecking = false;
                initialLoad = false;
            }
        };

        syncPlatformData(); // initial
        const interval = setInterval(syncPlatformData, 3000); // Polling real DB every 3s
        return () => clearInterval(interval);
    }, [user]);

    // Auto-scroll logs
    useEffect(() => {
        if (logsEndRef.current && logsEndRef.current.parentNode) {
            const parent = logsEndRef.current.parentNode;
            parent.scrollTo({
                top: parent.scrollHeight,
                behavior: 'smooth'
            });
        }
    }, [liveLogs]);

    if (!user) return null; // Or a loading spinner

    const navItems = [
        { label: './Dashboard', path: '/dashboard', action: () => navigate('/dashboard') },
