import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import LoginModal from '../components/LoginModal';
import SignupModal from '../components/SignupModal';
import Navbar from '../components/Navbar';
import {
  Calendar,
  EyeOff,
  Terminal,
  Clock,
  Trophy,
  Zap,
  Users,
  ArrowRight,
  Code,
  Swords,
  LayoutDashboard,
  ShieldCheck
} from 'lucide-react';
import { motion } from 'framer-motion';
import API_BASE from '../config/api';


export default function EventsPage() {
  const navigate = useNavigate();
  const [user, setUser] = useState(() => {
    const savedUser = localStorage.getItem('user');
    return savedUser ? JSON.parse(savedUser) : null;
  });
  const [showContent, setShowContent] = useState(() => {
    return !!sessionStorage.getItem('hasSeenDashboardEventsIntro');
  });
  const [isLoginOpen, setIsLoginOpen] = useState(false);
  const [isSignupOpen, setIsSignupOpen] = useState(false);

  const [isCodeModalOpen, setIsCodeModalOpen] = useState(false);
  const [accessCode, setAccessCode] = useState('');
  const [codeError, setCodeError] = useState('');

  const handleJoinClick = () => {
    setIsCodeModalOpen(true);
    setAccessCode('');
    setCodeError('');
  };

  const handleCodeSubmit = async (e) => {
    e.preventDefault();
    try {
      const response = await fetch(`${API_BASE}/api/events/verify`, {

        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          eventId: 'blind-coding',
          code: accessCode
        })
      });

      const data = await response.json();

      if (response.ok && data.success) {
        setIsCodeModalOpen(false);
        navigate('/competition/blind-coding/lobby');
      } else {
        setCodeError(data.message || 'Invalid Access Code. Please try again.');
      }
    } catch (error) {
      console.error(error);
      setCodeError('Connection error. Please check your network.');
    }
  };

  // Animation complete hone ke baad content show karo
  React.useEffect(() => {
    if (showContent) return;

    const timer = setTimeout(() => {
      setShowContent(true);
      sessionStorage.setItem('hasSeenDashboardEventsIntro', 'true');
    }, 3500); // 3.5 seconds animation

    return () => clearTimeout(timer);
  }, [showContent]);

  const openLogin = () => { setIsLoginOpen(true); setIsSignupOpen(false); };
  const closeLogin = () => setIsLoginOpen(false);
  const openSignup = () => { setIsSignupOpen(true); setIsLoginOpen(false); };
  const closeSignup = () => setIsSignupOpen(false);

  return (
    <>
      {/* Opening Logo Animation - Full Screen */}
      {!showContent && (
        <motion.div
          // ... (rest of animation code)
          initial={{ opacity: 1 }}
          animate={{ opacity: 1 }}
          exit={{ opacity: 0 }}
          transition={{ duration: 0.5 }}
          className="fixed inset-0 z-[9999] bg-gradient-to-br from-slate-50 via-white to-slate-100 dark:from-slate-950 dark:via-slate-900 dark:to-slate-950 flex items-center justify-center transition-colors duration-500"
        >
          <div className="relative">
            {/* Background Circle */}
            <motion.div
              initial={{ scale: 0.8, opacity: 0 }}
              animate={{ scale: 1, opacity: 1 }}
              transition={{ duration: 0.6, ease: "easeOut" }}
              className="relative w-80 h-80 bg-white dark:bg-slate-900 rounded-full flex items-center justify-center border-8 border-slate-100 dark:border-slate-800 shadow-2xl transition-colors duration-300"
            >
              {/* Eye Icon with entrance animation */}
              <motion.div
                initial={{ scale: 0, rotate: -180, opacity: 0 }}
                animate={{ scale: 1, rotate: 0, opacity: 1 }}
                transition={{
                  duration: 1,
                  delay: 0.3,
                  ease: [0.34, 1.56, 0.64, 1],
                  opacity: { duration: 0.4, delay: 0.3 }
                }}
                className="relative z-10"
              >
                <EyeOff className="w-32 h-32 text-slate-300" />
              </motion.div>

              {/* Dashed Circle with draw animation */}
              <motion.div
                initial={{ scale: 0, opacity: 0, rotate: -90 }}
                animate={{
                  scale: 1,
                  opacity: 1,
                  rotate: 0,
                }}
                transition={{
                  duration: 1.2,
                  delay: 1.3,
                  ease: "easeInOut"
                }}
                className="absolute inset-0 rounded-full border-4 border-dashed border-slate-300"
              >
                <motion.div
                  animate={{ rotate: 360 }}
                  transition={{
                    duration: 20,
                    repeat: Infinity,
                    ease: "linear",
                    delay: 2.5
                  }}
                  className="w-full h-full"
                />
              </motion.div>

              {/* Code Badge */}
              <motion.div
                initial={{ scale: 0, y: -20, opacity: 0 }}
                animate={{ scale: 1, y: 0, opacity: 1 }}
                transition={{
                  duration: 0.6,
                  delay: 2.2,
                  type: "spring",
                  stiffness: 200
                }}
                className="absolute -right-6 top-4 bg-gradient-to-br from-purple-500 to-indigo-600 p-5 rounded-2xl shadow-2xl"
              >
                <Code className="w-10 h-10 text-white" />
              </motion.div>
            </motion.div>

            {/* Title Text */}
            <motion.div
              initial={{ opacity: 0, y: 20 }}
              animate={{ opacity: 1, y: 0 }}
              transition={{ duration: 0.6, delay: 2.5 }}
              className="text-center mt-8"
            >
              <h2 className="text-3xl font-bold text-slate-900 dark:text-white font-mono transition-colors">Blind Coding</h2>
              <p className="text-slate-500 dark:text-slate-400 mt-2 transition-colors">Loading Event...</p>
            </motion.div>
          </div>
        </motion.div>
      )}

      {/* Main Page Content - Fades in after animation */}
      <motion.div
        initial={{ opacity: 0 }}
        animate={{ opacity: showContent ? 1 : 0 }}
        transition={{ duration: 0.8 }}
        className="min-h-screen bg-[#F8FAFC] dark:bg-slate-950 font-['JetBrains_Mono'] relative transition-colors duration-300"
      >
        {/* Navbar */}
        <Navbar
          items={[
            { label: './Dashboard', path: '/dashboard', action: () => navigate('/dashboard') },
            { label: './Events', path: '/dashboard/events', action: () => navigate('/dashboard/events') },
